SKILL = {'name': 'input_validation', 'keywords': ['input validation', 'type checking', 'error handling', 'division by zero', 'assertions', 'exception raising', 'numeric operations', 'edge cases'], 'prompt_fragment': 'Implement robust input validation for arithmetic operations. Verify types before computation and raise ValueError for invalid inputs or edge cases like division by zero. Use assertions to test valid operations, invalid type entries, and boundary conditions. Ensure consistent error messages and comprehensive test coverage for all functions.', 'example_code': "def suma(a, b):\n    if not isinstance(a, (int, float)) or not isinstance(b, (int, float)):\n        raise ValueError('Entradas no numéricas')\n    return a + b\n\ndef division(a, b):\n    if not isinstance(a, (int, float)) or not isinstance(b, (int, float)):\n        raise ValueError('Entradas no numéricas')\n    if b == 0:\n        raise ValueError('División por cero')\n    return a / b\n\n# Valid operations\nassert suma(2, 3) == 5\nassert division(10, 2) == 5.0\n\n# Invalid type handling\ntry:\n    suma('a', 1)\nexcept ValueError as e:\n    assert str(e) == 'Entradas no numéricas'\n\n# Division by zero\ntry:\n    division(10, 0)\nexcept ValueError as e:\n    assert str(e) == 'División por cero'"}
